export { DEFAULT_CONFIG };

export function loadConfig(cwd: string): { config: PipelineExtensionConfig; source: "file" | "defaults" } {
	const configPath = path.join(cwd, ".pi", "pi-pipeline.json");

	if (!fs.existsSync(configPath)) {
		return { config: structuredClone(DEFAULT_CONFIG), source: "defaults" };
	}

	try {
		const raw = fs.readFileSync(configPath, "utf-8");
		const parsed: unknown = JSON.parse(raw);

		if (typeof parsed !== "object" || parsed === null || Array.isArray(parsed)) {
			return { config: structuredClone(DEFAULT_CONFIG), source: "defaults" };
		}

		const user = parsed as Record<string, unknown>;
		const config = structuredClone(DEFAULT_CONFIG);

		if (typeof user.enabled === "boolean") config.enabled = user.enabled;

		// Merge clarification
		if (typeof user.clarification === "object" && user.clarification !== null && !Array.isArray(user.clarification)) {
			const c = user.clarification as Record<string, unknown>;
			if (typeof c.enabled === "boolean") config.clarification.enabled = c.enabled;
			if (typeof c.ambiguityThreshold === "number") config.clarification.ambiguityThreshold = c.ambiguityThreshold;
			if (c.mode === "auto" || c.mode === "manual") config.clarification.mode = c.mode;
			if (typeof c.maxQuestions === "number") config.clarification.maxQuestions = c.maxQuestions;
			if (typeof c.socraticForComplex === "boolean") config.clarification.socraticForComplex = c.socraticForComplex;
		}

		// Merge plan
		if (typeof user.plan === "object" && user.plan !== null && !Array.isArray(user.plan)) {
			const p = user.plan as Record<string, unknown>;
			if (typeof p.enabled === "boolean") config.plan.enabled = p.enabled;
			if (typeof p.noPlaceholders === "boolean") config.plan.noPlaceholders = p.noPlaceholders;
			if (typeof p.showInChunks === "boolean") config.plan.showInChunks = p.showInChunks;
			if (typeof p.maxTasksPerPlan === "number") config.plan.maxTasksPerPlan = p.maxTasksPerPlan;
			if (typeof p.deepeningEnabled === "boolean") config.plan.deepeningEnabled = p.deepeningEnabled;
		}

		// Merge verification
		if (typeof user.verification === "object" && user.verification !== null && !Array.isArray(user.verification)) {
			const v = user.verification as Record<string, unknown>;
			if (typeof v.enabled === "boolean") config.verification.enabled = v.enabled;
			if (Array.isArray(v.gates)) config.verification.gates = v.gates as string[];
			if (Array.isArray(v.blockingGates)) config.verification.blockingGates = v.blockingGates as string[];
			if (typeof v.stopTheLine === "boolean") config.verification.stopTheLine = v.stopTheLine;
			if (typeof v.freshContextVerification === "boolean") config.verification.freshContextVerification = v.freshContextVerification;
			if (typeof v.antiRationalization === "boolean") config.verification.antiRationalization = v.antiRationalization;
			if (typeof v.maxReviewIterations === "number") config.verification.maxReviewIterations = v.maxReviewIterations;
			if (typeof v.tddGate === "boolean") config.verification.tddGate = v.tddGate;
		}

		// Merge review
		if (typeof user.review === "object" && user.review !== null && !Array.isArray(user.review)) {
			const r = user.review as Record<string, unknown>;
			if (typeof r.enabled === "boolean") config.review.enabled = r.enabled;
			if (typeof r.twoStage === "boolean") config.review.twoStage = r.twoStage;
			if (Array.isArray(r.perspectives)) config.review.perspectives = r.perspectives as string[];
		}

		// Merge adaptive
		if (typeof user.adaptive === "object" && user.adaptive !== null && !Array.isArray(user.adaptive)) {
			const a = user.adaptive as Record<string, unknown>;
			if (typeof a.enabled === "boolean") config.adaptive.enabled = a.enabled;
			if (Array.isArray(a.simplePipeline)) config.adaptive.simplePipeline = a.simplePipeline as string[];
			if (Array.isArray(a.mediumPipeline)) config.adaptive.mediumPipeline = a.mediumPipeline as string[];
			if (Array.isArray(a.complexPipeline)) config.adaptive.complexPipeline = a.complexPipeline as string[];
		}

		return { config, source: "file" };
	} catch {
		return { config: structuredClone(DEFAULT_CONFIG), source: "defaults" };
	}
}

import type { AmbiguitySignal } from "../types.ts";

/** Count backtick-quoted or path-like file references in a message. */
export function mentionsFiles(message: string): number {
	// backtick-quoted paths: `src/foo.ts`
	const backtickMatches = message.match(/`[^`]+`/g);
	// path-like references: src/foo.ts, ./bar.ts
	const pathMatches = message.match(/(?:\.\/|\/)?(?:src|test|lib|dist|packages)\/\S+/g);
	return (backtickMatches?.length ?? 0) + (pathMatches?.length ?? 0);
}

/** Heuristic: does the message look like a coding task (vs a question)? */
export function looksLikeCodingTask(message: string): boolean {
	return /(?:fix|implement|add|create|remove|delete|update|change|refactor|build|write|set up|configure|install|migrate|port|optimize)\b/i.test(message);
}

/**
 * Detect ambiguity signals in a user message.
 * Implements 6 heuristics from SPEC §4.1.
 */
export function detectAmbiguity(message: string): AmbiguitySignal[] {
	const signals: AmbiguitySignal[] = [];

	// 1. Vague action verbs
	if (/improve|optimize|fix|enhance|refactor|clean up|better/i.test(message)) {
		signals.push({ type: "vague_action", score: 0.5 });
	}

	// 2. No specific files mentioned
	if (mentionsFiles(message) === 0 && looksLikeCodingTask(message)) {
		signals.push({ type: "no_files", score: 0.3 });
	}

	// 3. Architecture change implied
	if (/rewrite|migrate|replace|restructure|redesign/i.test(message)) {
		signals.push({ type: "architecture_change", score: 0.7 });
	}

	// 4. Security-sensitive
	if (/auth|password|token|secret|encrypt|permission|admin/i.test(message)) {
		signals.push({ type: "security_sensitive", score: 0.6 });
	}

	// 5. Multiple interpretations possible (short messages with vague pronouns)
	if (/\bit\b|\bthat\b|\bthis\b|\bthe issue\b|\bthe problem\b/i.test(message) && message.split(" ").length < 20) {
		signals.push({ type: "ambiguous_reference", score: 0.4 });
	}

	// 6. Scope unclear
	if (/\ball\b|\beverything\b|\bcompletely\b|\bentire\b/i.test(message)) {
		signals.push({ type: "unclear_scope", score: 0.4 });
	}

	return signals;
}

import type { AmbiguitySignal } from "../types.ts";

/**
 * Combine all ambiguity signal scores into a single total, capped at 1.0.
 */
export function totalAmbiguityScore(signals: AmbiguitySignal[]): number {
	return Math.min(1.0, signals.reduce((sum, s) => sum + s.score, 0));
}

import type { AmbiguitySignal, Question, Questionnaire } from "../types.ts";

/**
 * Generate a structured questionnaire based on detected ambiguity signals.
 * Each signal type maps to a specific question template.
 */
export function generateQuestionnaire(message: string, signals: AmbiguitySignal[]): Questionnaire {
	const questions: Question[] = [];
	const signalTypes = new Set(signals.map((s) => s.type));

	if (signalTypes.has("vague_action")) {
		questions.push({
			id: "q_vague_action",
			text: `What specifically should be done? The request "${message.slice(0, 80)}" uses vague terms.`,
			type: "single_choice",
			options: [
				"Add new functionality",
				"Fix an existing bug",
				"Improve performance",
				"Refactor for clarity",
				"Something else (please describe)",
			],
			required: true,
		});
	}

	if (signalTypes.has("no_files")) {
		questions.push({
			id: "q_no_files",
			text: "Which files or modules should be changed?",
			type: "text",
			required: true,
		});
	}

	if (signalTypes.has("architecture_change")) {
		questions.push({
			id: "q_architecture",
			text: "This sounds like an architecture change. What is the target architecture?",
			type: "text",
			required: true,
		});
	}

	if (signalTypes.has("security_sensitive")) {
		questions.push({
			id: "q_security",
			text: "Security-sensitive area detected. What security requirements apply?",
			type: "multi_choice",
			options: [
				"Input validation required",
				"Authentication/authorization change",
				"Data encryption at rest or in transit",
				"Audit logging needed",
				"No special security requirements",
			],
			required: true,
		});
	}

	if (signalTypes.has("ambiguous_reference")) {
		questions.push({
			id: "q_ambiguous_ref",
			text: "Could you clarify what you are referring to?",
			type: "text",
			required: true,
		});
	}

	if (signalTypes.has("unclear_scope")) {
		questions.push({
			id: "q_unclear_scope",
			text: "What is the specific scope of this change?",
			type: "single_choice",
			options: [
				"One file or function",
				"One module/feature",
				"Multiple modules",
				"Entire codebase",
				"Let me describe the scope",
			],
			required: true,
		});
	}

	return { questions };
}

/**
 * Format a questionnaire as a human-readable string.
 */
export function formatQuestionnaire(q: Questionnaire): string {
	const parts: string[] = [];
	let idx = 1;
	for (const question of q.questions) {
		let text = `${idx}. ${question.text}`;
		if (question.options && question.options.length > 0) {
			const letterOffset = "a".charCodeAt(0);
			text += "\n" + question.options.map((opt, i) => `   ${String.fromCharCode(letterOffset + i)}) ${opt}`).join("\n");
		}
		parts.push(text);
		idx++;
	}
	return parts.join("\n\n");
}

export interface SocraticPhase {
	name: string;
	prompt: string;
	questions: string[];
}

export const SOCRATIC_PHASES: SocraticPhase[] = [
	{
		name: "Scope Discovery",
		prompt: "What's the end goal? What should be different when this is done?",
		questions: [
			"What is the specific outcome you expect?",
			"What should be different after this change?",
			"Who are the users or consumers of this change?",
		],
	},
	{
		name: "Constraint Exploration",
		prompt: "Any constraints I should know about? Performance? Compatibility? Timeline?",
		questions: [
			"Are there performance requirements?",
			"Any backward compatibility constraints?",
			"What is the timeline or deadline?",
		],
	},
	{
		name: "Edge Case Discovery",
		prompt: "What happens at the boundaries? How should the system handle failures?",
		questions: [
			"What edge cases need to be handled?",
			"How should the system behave on error?",
			"Are there any known failure modes to prevent?",
		],
	},
	{
		name: "Acceptance Criteria",
		prompt: "How will you know this is done? What does 'done' look like?",
		questions: [
			"What are the acceptance criteria?",
			"How will you verify the change works correctly?",
			"What tests should pass?",
		],
	},
	{
		name: "Priority Clarification",
		prompt: "If tradeoffs are needed, what matters most?",
		questions: [
			"Speed or correctness — which matters more?",
			"Should I prioritize minimal changes or thorough coverage?",
			"Is there anything that is explicitly out of scope?",
		],
	},
];

/**
 * Generate Socratic questions for a given phase and complexity level.
 * For complex tasks, returns all questions for the current phase.
 * For simpler tasks, returns only the prompt.
 */
export function generateSocraticQuestions(message: string, complexity: string, phaseIndex: number): string[] {
	if (phaseIndex < 0 || phaseIndex >= SOCRATIC_PHASES.length) return [];
	const phase = SOCRATIC_PHASES[phaseIndex];
	if (complexity === "complex") {
		return [phase.prompt, ...phase.questions];
	}
	return [phase.prompt];
}

/**
 * Determine the next Socratic phase.
 * Advances if ambiguity score is low enough; stays on current phase otherwise.
 */
export function nextPhase(current: number, ambiguityScore: number): number {
	if (current >= SOCRATIC_PHASES.length - 1) return current;
	if (ambiguityScore < 0.3) return current + 1;
	return current;
}

import type { PlanModeState, Plan, PlanTask, PipelineState } from "../types.ts";

/** Valid state transitions for the plan mode state machine. */
const TRANSITIONS: Record<PlanModeState, PlanModeState[]> = {
	"IDLE": ["GATHERING"],
	"GATHERING": ["SPEC'ING", "IDLE"],
	"SPEC'ING": ["PLANNING", "GATHERING"],
	"PLANNING": ["READY", "SPEC'ING"],
	"READY": ["EXECUTING", "PLANNING"],
	"EXECUTING": ["REVIEWING", "READY"],
	"REVIEWING": ["COMPLETE", "EXECUTING"],
	"COMPLETE": ["IDLE"],
};

/**
 * Check if a transition from `from` to `to` is valid.
 */
export function canTransition(from: PlanModeState, to: PlanModeState): boolean {
	return TRANSITIONS[from]?.includes(to) ?? false;
}

/**
 * Attempt a state transition. Returns the new state on success, or throws.
 */
export function transition(state: PipelineState, to: PlanModeState): PipelineState {
	if (!canTransition(state.mode, to)) {
		throw new Error(`Invalid state transition: ${state.mode} → ${to}`);
	}
	return { ...state, mode: to };
}

/**
 * Create a new plan with empty tasks in the GATHERING state.
 */
export function createPlan(title: string): Plan {
	return {
		title,
		spec: "",
		tasks: [],
		issues: [],
		createdAt: new Date().toISOString(),
		state: "GATHERING",
	};
}

/**
 * Get the ordered tasks from a plan (sorted by dependency).
 */
export function orderedTasks(plan: Plan): PlanTask[] {
	return [...plan.tasks].sort((a, b) => {
		// If a depends on b, a comes after
		if (a.depends_on.includes(b.id)) return 1;
		// If b depends on a, b comes after
		if (b.depends_on.includes(a.id)) return -1;
		return 0;
	});
}

/**
 * Get the status string for the current plan state.
 */
export function planStatus(state: PipelineState): string {
	const lines: string[] = [];
	lines.push(`State: ${state.mode}`);
	if (state.plan) {
		lines.push(`Plan: ${state.plan.title}`);
		lines.push(`Tasks: ${state.plan.tasks.length}`);
		const completed = state.currentTaskIndex;
		lines.push(`Progress: ${completed}/${state.plan.tasks.length}`);
		if (state.plan.issues.length > 0) {
			lines.push(`Issues: ${state.plan.issues.join(", ")}`);
		}
	}
	lines.push(`Complexity: ${state.complexity}`);
	lines.push(`Ambiguity: ${state.ambiguityScore.toFixed(2)}`);
	return lines.join("\n");
}

import type { Plan, PlanTask, ReviewChecklistItem } from "../types.ts";

export interface SpecSection {
	heading: string;
	content: string;
}

/**
 * Generate a spec from gathered requirements.
 */
export function generateSpec(
	title: string,
	context: string,
	requirements: string[],
	scopeIn: string[],
	scopeOut: string[],
	acceptanceCriteria: string[],
	technicalNotes: string,
	filesLikelyAffected: string[],
): Plan {
	const sections: SpecSection[] = [
		{ heading: "Context", content: context },
		{
			heading: "Requirements",
			content: requirements.map((r) => `- ${r}`).join("\n"),
		},
		{
			heading: "Scope",
			content:
				"### In Scope\n" +
				scopeIn.map((s) => `- ${s}`).join("\n") +
				"\n### Out of Scope\n" +
				scopeOut.map((s) => `- ${s}`).join("\n"),
		},
		{
			heading: "Acceptance Criteria",
			content: acceptanceCriteria.map((c) => `- [ ] ${c}`).join("\n"),
		},
		{ heading: "Technical Notes", content: technicalNotes },
		{
			heading: "Files Likely Affected",
			content: filesLikelyAffected.map((f) => `- \`${f}\``).join("\n"),
		},
	];

	const spec = sections.map((s) => `## ${s.heading}\n\n${s.content}`).join("\n\n");

	return {
		title,
		spec: `# Spec: ${title}\n\n${spec}`,
		tasks: [],
		issues: [],
		createdAt: new Date().toISOString(),
		state: "SPEC'ING",
	};
}

/**
 * Format spec sections as an array of chunk strings for incremental display.
 */
export function chunkSpec(plan: Plan): string[] {
	const lines = plan.spec.split("\n");
	const chunks: string[] = [];
	let current: string[] = [];

	for (const line of lines) {
		if (line.startsWith("## ") && current.length > 0) {
			chunks.push(current.join("\n"));
			current = [];
		}
		current.push(line);
	}
	if (current.length > 0) {
		chunks.push(current.join("\n"));
	}

	return chunks;
}

/**
 * Generate acceptance criteria checklist from plan tasks.
 */
export function acceptanceCriteriaFromTasks(tasks: PlanTask[]): ReviewChecklistItem[] {
	return tasks.map((t) => ({
		label: `Task ${t.id}: ${t.title}`,
		status: "UNCLEAR" as const,
		evidence: "",
	}));
}

import type { PlanTask, TaskComplexity } from "../types.ts";

let taskCounter = 0;

/**
 * Reset the internal task counter (for testing).
 */
export function resetCounter(): void {
	taskCounter = 0;
}

/**
 * Generate a task ID like "01", "02", etc.
 */
export function nextTaskId(): string {
	taskCounter++;
	return String(taskCounter).padStart(2, "0");
}

/**
 * Create a single plan task with the given properties.
 */
export function createTask(
	title: string,
	description: string,
	files: string[],
	opts?: {
		testCommand?: string;
		depends_on?: string[];
		complexity?: TaskComplexity;
		model?: string;
	},
): PlanTask {
	return {
		id: nextTaskId(),
		title,
		description,
		files,
		testCommand: opts?.testCommand,
		depends_on: opts?.depends_on ?? [],
		complexity: opts?.complexity ?? "standard",
		model: opts?.model,
	};
}

/**
 * Decompose a set of requirements into vertical-slice tasks.
 * Each task targets 2-5 minutes of work with complete end-to-end functionality.
 */
export function decomposeIntoTasks(
	requirements: string[],
	fileMap: Record<string, string[]>,
): PlanTask[] {
	resetCounter();
	const tasks: PlanTask[] = [];

	for (const req of requirements) {
		const files = fileMap[req] ?? [];
		tasks.push(
			createTask(
				req.length > 60 ? req.slice(0, 57) + "..." : req,
				req,
				files,
				{
					testCommand: files.length > 0 ? `npm test` : undefined,
					complexity: inferComplexity(req, files),
				},
			),
		);
	}

	return tasks;
}

function inferComplexity(_req: string, files: string[]): TaskComplexity {
	if (files.length > 4) return "architecture";
	if (files.length > 1) return "standard";
	return "mechanical";
}

import type { PlanTask } from "../types.ts";

/**
 * Perform a topological sort of tasks based on their `depends_on` fields.
 * Returns tasks in valid execution order.
 * Throws if a circular dependency is detected.
 */
export function topologicalSort(tasks: PlanTask[]): PlanTask[] {
	const taskMap = new Map<string, PlanTask>();
	for (const t of tasks) taskMap.set(t.id, t);

	const visited = new Set<string>();
	const visiting = new Set<string>();
	const result: PlanTask[] = [];

	function visit(id: string): void {
		if (visited.has(id)) return;
		if (visiting.has(id)) {
			throw new Error(`Circular dependency detected involving task: ${id}`);
		}
		const task = taskMap.get(id);
		if (!task) throw new Error(`Unknown task dependency: ${id}`);

		visiting.add(id);
		for (const dep of task.depends_on) {
			visit(dep);
		}
		visiting.delete(id);
		visited.add(id);
		result.push(task);
	}

	for (const t of tasks) {
		visit(t.id);
	}

	return result;
}

/**
 * Validate that all depends_on references exist in the task list.
 * Returns an array of error messages.
 */
export function validateDependencies(tasks: PlanTask[]): string[] {
	const errors: string[] = [];
	const ids = new Set(tasks.map((t) => t.id));

	for (const task of tasks) {
		for (const dep of task.depends_on) {
			if (!ids.has(dep)) {
				errors.push(`Task ${task.id} depends on unknown task: ${dep}`);
			}
		}
	}

	return errors;
}

import type { PlanTask } from "../types.ts";

const PLACEHOLDER_PATTERNS = [
	/\bTBD\b/i,
	/\btodo\b/i,
	/\bFIXME\b/i,
	/\badd.*later\b/i,
	/\bimplement.*later\b/i,
	/\betc\.\b/i,
	/\band so on\b/i,
	/\bsimilar to\b/i,
	/\bsame as before\b/i,
];

/**
 * Validate a list of plan tasks for placeholder content.
 * Returns an array of error messages for each violation.
 */
export function validatePlan(tasks: PlanTask[]): string[] {
	const errors: string[] = [];

	for (const task of tasks) {
		for (const pattern of PLACEHOLDER_PATTERNS) {
			if (pattern.test(task.description)) {
				errors.push(`Task ${task.id}: Placeholder detected: "${task.description}"`);
			}
		}
		if (task.files.length === 0) {
			errors.push(`Task ${task.id}: No files specified`);
		}
		if (!task.testCommand) {
			errors.push(`Task ${task.id}: No test/verification command specified`);
		}
	}

	return errors;
}

/**
 * Check if a single task description contains placeholders.
 */
export function hasPlaceholders(description: string): boolean {
	return PLACEHOLDER_PATTERNS.some((p) => p.test(description));
}

import type { Plan, PlanTask } from "../types.ts";
import { validatePlan } from "./plan-validator.ts";

/**
 * Deepen a plan by refining low-confidence (architecture) tasks.
 * Returns a new plan with refined tasks.
 */
export function deepenPlan(
	plan: Plan,
	analyzer: (task: PlanTask) => PlanTask,
): Plan {
	const refinedTasks = plan.tasks.map((task) => {
		if (task.complexity === "architecture") {
			return analyzer(task);
		}
		return task;
	});

	const issues = validatePlan(refinedTasks);
	return {
		...plan,
		tasks: refinedTasks,
		issues,
		state: "PLANNING",
	};
}

import type { Milestone, PlanTask } from "../types.ts";

/**
 * Create milestones by grouping tasks that share the same dependency level.
 * Tasks with no dependencies are milestone 1, tasks depending only on milestone 1
 * are milestone 2, etc.
 */
export function createMilestones(tasks: PlanTask[]): Milestone[] {
	const taskMap = new Map(tasks.map((t) => [t.id, t]));
	const milestoneOf = new Map<string, number>();

	function getLevel(id: string): number {
		if (milestoneOf.has(id)) return milestoneOf.get(id)!;
		const task = taskMap.get(id);
		if (!task || task.depends_on.length === 0) {
			milestoneOf.set(id, 1);
			return 1;
		}
		const maxDepLevel = Math.max(...task.depends_on.map((d) => getLevel(d)));
		const level = maxDepLevel + 1;
		milestoneOf.set(id, level);
		return level;
	}

	for (const task of tasks) {
		getLevel(task.id);
	}

	// Group by level
	const groups = new Map<number, string[]>();
	for (const [id, level] of milestoneOf) {
		if (!groups.has(level)) groups.set(level, []);
		groups.get(level)!.push(id);
	}

	const milestones: Milestone[] = [];
	const sortedLevels = [...groups.keys()].sort((a, b) => a - b);
	for (const level of sortedLevels) {
		const taskIds = groups.get(level)!;
		const titles = taskIds.map((id) => taskMap.get(id)?.title).filter(Boolean);
		milestones.push({
			id: `M${level}`,
			title: `Milestone ${level}: ${titles.join(", ")}`,
			taskIds,
			completed: false,
		});
	}

	return milestones;
}

/**
 * Mark a milestone as completed if all its tasks are done.
 */
export function completeMilestone(milestone: Milestone, completedTaskIds: Set<string>): Milestone {
	const allDone = milestone.taskIds.every((id) => completedTaskIds.has(id));
	return { ...milestone, completed: allDone };
}

