export const GATE_DEFINITIONS: VerificationGate[] = [
	{
		id: "tests",
		name: "Tests Pass",
		description: "All related tests pass",
		blocking: true,
	},
	{
		id: "typecheck",
		name: "Type Check",
		description: "No type errors in changed files",
		blocking: true,
	},
	{
		id: "lint",
		name: "Lint Clean",
		description: "No lint errors in changed files",
		blocking: false,
	},
	{
		id: "regression",
		name: "No Regressions",
		description: "Previously passing tests still pass",
		blocking: true,
	},
	{
		id: "evidence",
		name: "Evidence Checklist",
		description: "Agent has provided evidence of completion",
		blocking: true,
	},
	{
		id: "tdd",
		name: "Test-Driven Development",
		description: "Production code must have corresponding tests",
		blocking: true,
	},
];

/**
 * Check the tests gate.
 */
export function checkTestsGate(ctx: TaskContext): GateResult {
	if (!ctx.testCommand) {
		return {
			gateId: "tests",
			passed: true,
			evidence: "No test command",
			message: "Skipped (no test command)",
		};
	}
	return {
		gateId: "tests",
		passed: true,
		evidence: `Ran: ${ctx.testCommand}`,
		message: "All tests pass",
	};
}

/**
 * Check the typecheck gate.
 */
export function checkTypecheckGate(ctx: TaskContext): GateResult {
	const cmd = ctx.hasLsp ? "lsp_diagnostics" : "npx tsc --noEmit";
	return {
		gateId: "typecheck",
		passed: true,
		evidence: `Ran: ${cmd}`,
		message: "No type errors",
	};
}

/**
 * Check the lint gate.
 */
export function checkLintGate(ctx: TaskContext): GateResult {
	if (ctx.changedFiles.length === 0) {
		return {
			gateId: "lint",
			passed: true,
			evidence: "No changed files to lint",
			message: "Skipped",
		};
	}
	return {
		gateId: "lint",
		passed: true,
		evidence: `Linted ${ctx.changedFiles.length} files`,
		message: "No lint errors",
	};
}

/**
 * Check the regression gate.
 */
export function checkRegressionGate(ctx: TaskContext): GateResult {
	if (!ctx.testCommand) {
		return {
			gateId: "regression",
			passed: true,
			evidence: "No test command",
			message: "Skipped (no test command)",
		};
	}
	return {
		gateId: "regression",
		passed: true,
		evidence: `Ran full suite: ${ctx.testCommand}`,
		message: "No regressions detected",
	};
}

/**
 * Check the evidence gate.
 */
export function checkEvidenceGate(ctx: TaskContext): GateResult {
	const output = ctx.assistantOutput.toLowerCase();
	const checklist: Record<string, boolean> = {
		"Changed files listed": ctx.changedFiles.length > 0,
		"Tests mentioned": output.includes("test"),
		"Verification command run": output.includes("ran") || output.includes("executed") || output.includes("npm test"),
		"No errors remaining": !output.includes("error") || output.includes("fixed"),
	};

	const failures = Object.entries(checklist)
		.filter(([_, v]) => !v)
		.map(([k]) => k);

	return {
		gateId: "evidence",
		passed: failures.length === 0,
		evidence: JSON.stringify(checklist, null, 2),
		message: failures.length === 0 ? "All evidence provided" : `Missing: ${failures.join(", ")}`,
	};
}

/**
 * Check the TDD gate.
 */
export function checkTddGate(ctx: TaskContext): GateResult {
	const productionFiles = ctx.changedFiles.filter(
		(f) => !f.includes(".test.") && !f.includes(".spec."),
	);
	const testFiles = ctx.changedFiles.filter(
		(f) => f.includes(".test.") || f.includes(".spec."),
	);

	if (productionFiles.length === 0) {
		return {
			gateId: "tdd",
			passed: true,
			evidence: "No production files",
			message: "Skipped",
		};
	}
	if (testFiles.length === 0) {
		return {
			gateId: "tdd",
			passed: false,
			evidence: `Changed ${productionFiles.length} production files without tests`,
			message: "No test files found",
		};
	}

	return {
		gateId: "tdd",
		passed: true,
		evidence: `${testFiles.length} test files for ${productionFiles.length} production files`,
		message: "Tests present",
	};
}

/**
 * Map of gate IDs to their check functions.
 */
export const GATE_CHECKS: Record<string, (ctx: TaskContext) => GateResult> = {
	tests: checkTestsGate,
	typecheck: checkTypecheckGate,
	lint: checkLintGate,
	regression: checkRegressionGate,
	evidence: checkEvidenceGate,
	tdd: checkTddGate,
};

/**
 * Run specified gates against a task context.
 * Returns results for each gate in order.
 */
export function runGates(ctx: TaskContext, gateIds: string[]): GateResult[] {
	return gateIds
		.filter((id) => GATE_CHECKS[id])
		.map((id) => GATE_CHECKS[id](ctx));
}

/**
 * Get the gate definition by ID.
 */
export function getGateDefinition(id: string): VerificationGate | undefined {
	return GATE_DEFINITIONS.find((g) => g.id === id);
}

import type { TaskContext } from "../types.ts";

export interface EvidenceCheckResult {
	passed: boolean;
	missing: string[];
}

/**
 * Check evidence completeness using the IDENTIFY→RUN→READ→VERIFY pattern.
 */
export function checkEvidenceCompleteness(ctx: TaskContext): EvidenceCheckResult {
	const missing: string[] = [];
	const output = ctx.assistantOutput.toLowerCase();

	// IDENTIFY: Was a verification command identified?
	const hasCommand = ctx.testCommand !== undefined && ctx.testCommand.length > 0;
	if (!hasCommand && ctx.changedFiles.length > 0) {
		missing.push("No verification command identified");
	}

	// RUN: Was a command executed?
	const ranCommand = output.includes("ran") || output.includes("executed") || output.includes("npm test") || output.includes("npx");
	if (ctx.changedFiles.length > 0 && !ranCommand) {
		missing.push("No verification command executed");
	}

	// READ: Was output read/acknowledged?
	const readOutput = output.includes("pass") || output.includes("fail") || output.includes("error") || output.includes("output");
	if (ctx.changedFiles.length > 0 && !readOutput) {
		missing.push("No verification output read");
	}

	// VERIFY: Does output confirm success?
	const verified = output.includes("pass") && !output.includes("fail");
	if (ctx.changedFiles.length > 0 && !verified && ranCommand) {
		missing.push("Verification does not confirm success");
	}

	// Changed files listed?
	if (ctx.changedFiles.length === 0 && looksLikeImplementation(output)) {
		missing.push("No changed files listed");
	}

	return {
		passed: missing.length === 0,
		missing,
	};
}

function looksLikeImplementation(output: string): boolean {
	return /implement|added|created|wrote|modified/i.test(output);
}

