export function matchAntiRationalization(text: string): AntiRationalizationEntry | undefined {
	const lower = text.toLowerCase();
	return ANTI_RATIONALIZATION.find((entry) => lower.includes(entry.excuse.toLowerCase()));
}

import type { GateResult } from "../types.ts";

export interface StopTheLineResult {
	blocked: boolean;
	failedGates: string[];
}

/**
 * Check if stop-the-line should be triggered.
 * If any blocking gate failed, block all subsequent work.
 */
export function checkStopTheLine(
	results: GateResult[],
	blockingGateIds: string[],
): StopTheLineResult {
	const blockingSet = new Set(blockingGateIds);
	const failedGates = results
		.filter((r) => !r.passed && blockingSet.has(r.gateId))
		.map((r) => r.gateId);

	return {
		blocked: failedGates.length > 0,
		failedGates,
	};
}

/**
 * Format a stop-the-line message.
 */
export function formatStopTheLine(result: StopTheLineResult): string {
	if (!result.blocked) return "";
	return `STOP: Verification gate(s) failed: ${result.failedGates.join(", ")}.\nAll work is blocked until these gates pass.`;
}

import type { Plan } from "../types.ts";

export interface FreshContextConfig {
	inherit: string[];
	exclude: string[];
	freshContext: boolean;
}

/**
 * Build a fresh-context verification config for a verifier subagent.
 * The verifier can see the plan and changed files but NOT the
 * implementation chat, previous reviews, or agent rationale.
 */
export function buildFreshContextConfig(_plan: Plan): FreshContextConfig {
	return {
		inherit: ["plan", "changed_files"],
		exclude: ["implementation_chat", "previous_reviews", "agent_rationale"],
		freshContext: true,
	};
}

/**
 * Validate that a fresh-context config is correct.
 */
export function validateFreshContextConfig(config: FreshContextConfig): string[] {
	const errors: string[] = [];
	if (!config.inherit.includes("plan")) {
		errors.push("Fresh context config must inherit 'plan'");
	}
	if (!config.inherit.includes("changed_files")) {
		errors.push("Fresh context config must inherit 'changed_files'");
	}
	if (!config.exclude.includes("implementation_chat")) {
		errors.push("Fresh context config must exclude 'implementation_chat'");
	}
	if (!config.freshContext) {
		errors.push("Fresh context must be enabled");
	}
	return errors;
}

