import type { ReviewIteration, ReviewChecklistItem } from "../types.ts";

export interface ReviewLoopConfig {
	maxIterations: number;
}

const DEFAULT_CONFIG: ReviewLoopConfig = {
	maxIterations: 3,
};

/**
 * Run the review loop: implementer → reviewer → fix, up to maxIterations.
 * Returns the iteration history.
 */
export function executeReviewLoop(
	stage: "spec_compliance" | "code_quality",
	reviewer: (iteration: number) => ReviewChecklistItem[],
	config: ReviewLoopConfig = DEFAULT_CONFIG,
): ReviewIteration[] {
	const iterations: ReviewIteration[] = [];

	for (let i = 1; i <= config.maxIterations; i++) {
		const findings = reviewer(i);
		const passed = findings.every((f) => f.status !== "FAIL");

		iterations.push({
			stage,
			iteration: i,
			findings,
			passed,
		});

		if (passed) break;
	}

	return iterations;
}

/**
 * Check if the review loop has been exhausted without passing.
 */
export function isLoopExhausted(iterations: ReviewIteration[]): boolean {
	if (iterations.length === 0) return false;
	const last = iterations[iterations.length - 1];
	return !last.passed;
}

/**
 * Get a summary of review iterations.
 */
export function reviewLoopSummary(iterations: ReviewIteration[]): string {
	if (iterations.length === 0) return "No review iterations";

	const lines: string[] = [];
	for (const iter of iterations) {
		const failures = iter.findings.filter((f) => f.status === "FAIL").length;
		const status = iter.passed ? "PASSED" : `FAILED (${failures} issues)`;
		lines.push(
			`${iter.stage} iteration ${iter.iteration}: ${status}`,
		);
	}

	return lines.join("\n");
}

import type { ComplexitySignals, ComplexityLevel } from "../types.ts";

/**
 * Detect task complexity from a set of signals.
 * Returns "simple", "medium", or "complex" based on the SPEC §8.1 algorithm.
 */
export function detectComplexity(signals: ComplexitySignals): ComplexityLevel {
	let score = 0;

	if (signals.fileCount > 5) score += 3;
	else if (signals.fileCount > 2) score += 1;

	if (signals.isNewFeature) score += 2;
	if (signals.touchesArchitecture) score += 3;
	if (signals.hasDependencies) score += 2;
	if (signals.securitySensitive) score += 1;
	if (signals.estimatedLines > 200) score += 2;
	if (signals.hasTestsNeeded) score += 1;

	if (score <= 2) return "simple";
	if (score <= 5) return "medium";
	return "complex";
}

/**
 * Create a complexity signals object from heuristics.
 */
export function createSignals(opts: Partial<ComplexitySignals>): ComplexitySignals {
	return {
		fileCount: opts.fileCount ?? 0,
		isNewFeature: opts.isNewFeature ?? false,
		touchesArchitecture: opts.touchesArchitecture ?? false,
		hasDependencies: opts.hasDependencies ?? false,
		securitySensitive: opts.securitySensitive ?? false,
		estimatedLines: opts.estimatedLines ?? 0,
		hasTestsNeeded: opts.hasTestsNeeded ?? false,
	};
}

import type { ComplexityLevel, PipelinePhase } from "../types.ts";

/**
 * Select a model based on the current pipeline phase and task complexity.
 * Returns a model hint string or undefined for the default model.
 */
export function selectModel(
	complexity: ComplexityLevel,
	phase: PipelinePhase,
): string | undefined {
	// Verification and review always get the strongest model
	if (phase === "verification" || phase === "review") return "strongest";

	// Architecture and planning always get the strongest model
	if (phase === "architecture" || phase === "planning") return "strongest";

	// Simple tasks get the fast-cheap model
	if (complexity === "simple") return "fast-cheap";

	// Medium tasks use the default model
	if (complexity === "medium") return undefined;

	// Complex tasks get the strongest model
	if (complexity === "complex") return "strongest";

	return undefined;
}

import type { ComplexityLevel } from "../types.ts";
import type { PipelineExtensionConfig } from "../config.ts";

export interface PipelineDefinition {
	level: ComplexityLevel;
	steps: string[];
}

/**
 * Select the appropriate pipeline based on complexity level.
 */
export function selectPipeline(
	complexity: ComplexityLevel,
	config: PipelineExtensionConfig,
): PipelineDefinition {
	switch (complexity) {
		case "simple":
			return { level: "simple", steps: [...config.adaptive.simplePipeline] };
		case "medium":
			return { level: "medium", steps: [...config.adaptive.mediumPipeline] };
		case "complex":
			return { level: "complex", steps: [...config.adaptive.complexPipeline] };
	}
}

/**
 * Get a human-readable description of the pipeline.
 */
export function describePipeline(pipeline: PipelineDefinition): string {
	return `Pipeline (${pipeline.level}): ${pipeline.steps.join(" → ")}`;
}

/**
 * Check if a step exists in the pipeline.
 */
export function hasStep(pipeline: PipelineDefinition, step: string): boolean {
	return pipeline.steps.includes(step);
}

import type { PipelineState, Plan, PlanTask } from "../types.ts";
import type { PipelineExtensionConfig } from "../config.ts";
import { detectAmbiguity } from "../clarify/ambiguity.ts";
import { totalAmbiguityScore } from "../clarify/scoring.ts";
import { generateQuestionnaire, formatQuestionnaire } from "../clarify/questionnaire.ts";
import { generateSocraticQuestions, SOCRATIC_PHASES } from "../clarify/socratic.ts";
import { validatePlan } from "../plan/plan-validator.ts";
import { deepenPlan } from "../plan/deepen.ts";
import { planStatus, transition, createPlan } from "../plan/plan-mode.ts";

export interface PlanCommandResult {
	message: string;
	state: PipelineState;
	plan?: Plan;
}

/**
 * Handle /plan command: enter plan mode and start gathering requirements.
 */
export function handlePlan(
	args: string,
	state: PipelineState,
	config: PipelineExtensionConfig,
): PlanCommandResult {
	const task = args.trim();

	if (!task) {
		return {
			message: "What would you like to plan? Please describe the task or feature.",
			state: { ...state, mode: "GATHERING" },
		};
	}

	// Detect ambiguity
	const signals = detectAmbiguity(task);
	const score = totalAmbiguityScore(signals);
	const newState: PipelineState = {
		...state,
		mode: "GATHERING",
		ambiguityScore: score,
		plan: createPlan(task),
	};

	if (score > config.clarification.ambiguityThreshold && config.clarification.enabled) {
		const questionnaire = generateQuestionnaire(task, signals);
		const formatted = formatQuestionnaire(questionnaire);
		return {
			message: `I'd like to clarify before starting:\n\n${formatted}`,
			state: newState,
			plan: newState.plan ?? undefined,
		};
	}

	return {
		message: `Planning: "${task}"\n\nAmbiguity score: ${score.toFixed(2)} — no clarification needed. Generating spec...`,
		state: { ...newState, mode: "SPEC'ING" },
		plan: newState.plan ?? undefined,
	};
}

/**
 * Handle /plan deepen: deepen the current plan.
 */
export function handlePlanDeepen(
	state: PipelineState,
	analyzer: (task: PlanTask) => PlanTask,
): PlanCommandResult {
	if (!state.plan) {
		return {
			message: "No plan to deepen. Use /plan first.",
			state,
		};
	}

	const deepened = deepenPlan(state.plan, analyzer);
	const newState: PipelineState = { ...state, plan: deepened };

	if (deepened.issues.length > 0) {
		return {
			message: `Plan deepened with issues:\n${deepened.issues.map((i) => `- ${i}`).join("\n")}`,
			state: newState,
			plan: deepened,
		};
	}

	return {
		message: `Plan deepened successfully. ${deepened.tasks.length} tasks ready.`,
		state: newState,
		plan: deepened,
	};
}

/**
 * Handle /plan go: start execution of the approved plan.
 */
export function handlePlanGo(state: PipelineState): PlanCommandResult {
	if (!state.plan) {
		return { message: "No plan to execute. Use /plan first.", state };
	}

	if (state.mode !== "READY") {
		return {
			message: `Cannot start execution from state ${state.mode}. Plan must be in READY state.`,
			state,
		};
	}

	const errors = validatePlan(state.plan.tasks);
	if (errors.length > 0) {
		return {
			message: `Plan has validation errors:\n${errors.map((e) => `- ${e}`).join("\n")}\n\nFix these before executing.`,
			state,
		};
	}

	try {
		const newState = transition(state, "EXECUTING");
		return {
			message: `Executing plan: "${state.plan.title}"\n${state.plan.tasks.length} tasks to run.`,
			state: newState,
		};
	} catch (err) {
		return {
			message: `Cannot transition to EXECUTING: ${(err as Error).message}`,
			state,
		};
	}
}

/**
 * Handle /plan status: show current plan status.
 */
export function handlePlanStatus(state: PipelineState): PlanCommandResult {
	return {
		message: planStatus(state),
		state,
	};
}

import type { PipelineState } from "../types.ts";
import type { ReviewStage } from "../types.ts";
import { createSpecComplianceReview, enforceStageOrdering, formatStageReview } from "../review/two-stage.ts";

export interface ReviewCommandResult {
	message: string;
	state: PipelineState;
}

/**
 * Handle /plan review: run two-stage review on the current plan.
 */
export function handlePlanReview(
	state: PipelineState,
	stage1: ReviewStage,
	stage2?: ReviewStage,
): ReviewCommandResult {
	if (!state.plan) {
		return { message: "No plan to review. Use /plan first.", state };
	}

	// Stage 1: Spec compliance
	const stage1Result = stage1;
	const ordering = enforceStageOrdering(stage1Result);

	const parts: string[] = [];
	parts.push(formatStageReview(stage1Result));

	if (!ordering.canProceed) {
		parts.push(`\n${ordering.message}`);
		return { message: parts.join("\n"), state };
	}

	// Stage 2: Code quality (only if stage 1 passed)
	if (stage2) {
		parts.push("");
		parts.push(formatStageReview(stage2));
	} else {
		parts.push("\nStage 1 passed. Ready for Stage 2 (code quality review).");
	}

	return { message: parts.join("\n"), state };
}

import type { PipelineState, TaskContext, GateResult } from "../types.ts";
import type { PipelineExtensionConfig } from "../config.ts";
import { runGates, GATE_CHECKS } from "../verify/gates.ts";
import { checkEvidenceCompleteness } from "../verify/evidence.ts";
import { checkStopTheLine, formatStopTheLine } from "../verify/stop-the-line.ts";
import { matchAntiRationalization } from "../verify/anti-rationalization.ts";

export interface VerifyCommandResult {
	message: string;
	state: PipelineState;
	results?: GateResult[];
}

/**
 * Handle /verify: run verification gates.
 */
export function handleVerify(
	state: PipelineState,
	ctx: TaskContext,
	config: PipelineExtensionConfig,
): VerifyCommandResult {
	if (!config.verification.enabled) {
		return { message: "Verification gates are disabled.", state };
	}

	const gateIds = [...config.verification.gates];
	if (config.verification.tddGate && !gateIds.includes("tdd")) {
		gateIds.push("tdd");
	}

	const results = runGates(ctx, gateIds);

	// Check stop-the-line
	if (config.verification.stopTheLine) {
		const stopResult = checkStopTheLine(results, config.verification.blockingGates);
		if (stopResult.blocked) {
			return {
				message: formatStopTheLine(stopResult) +
					"\n\nGate results:\n" +
					results.map((r) => `  ${r.passed ? "✅" : "❌"} ${r.gateId}: ${r.message}`).join("\n"),
				state,
				results,
			};
		}
	}

	const passed = results.every((r) => r.passed);
	const summary = results.map((r) => `  ${r.passed ? "✅" : "❌"} ${r.gateId}: ${r.message}`).join("\n");

	return {
		message: passed ? `All gates passed!\n${summary}` : `Some gates failed:\n${summary}`,
		state,
		results,
	};
}

/**
 * Handle /verify evidence: show evidence checklist.
 */
export function handleVerifyEvidence(
	state: PipelineState,
	ctx: TaskContext,
): VerifyCommandResult {
	const evidence = checkEvidenceCompleteness(ctx);

	// Check for anti-rationalization in output
	const antiRat = matchAntiRationalization(ctx.assistantOutput);

	const parts: string[] = [];
	parts.push("Evidence Checklist:");
	if (evidence.missing.length === 0) {
		parts.push("  ✅ All evidence provided");
	} else {
		for (const item of evidence.missing) {
			parts.push(`  ❌ ${item}`);
		}
	}

	if (antiRat) {
		parts.push("");
		parts.push(`⚠️ Anti-rationalization detected:`);
		parts.push(`  Excuse: "${antiRat.excuse}"`);
		parts.push(`  Reality: "${antiRat.reality}"`);
	}

	return {
		message: parts.join("\n"),
		state,
	};
}

import type { PipelineState } from "../types.ts";
import type { PipelineExtensionConfig } from "../config.ts";
import { detectAmbiguity } from "../clarify/ambiguity.ts";
import { totalAmbiguityScore } from "../clarify/scoring.ts";
import { generateQuestionnaire, formatQuestionnaire } from "../clarify/questionnaire.ts";
import { generateSocraticQuestions, SOCRATIC_PHASES } from "../clarify/socratic.ts";

export interface ClarifyCommandResult {
	message: string;
	state: PipelineState;
}

/**
 * Handle /clarify: force clarification of the given message.
 */
export function handleClarify(
	message: string,
	state: PipelineState,
	config: PipelineExtensionConfig,
): ClarifyCommandResult {
	const signals = detectAmbiguity(message);
	const score = totalAmbiguityScore(signals);

	const newState: PipelineState = { ...state, ambiguityScore: score };

	// If complex, use Socratic interview
	if (state.complexity === "complex" && config.clarification.socraticForComplex) {
		const questions = generateSocraticQuestions(message, "complex", state.socraticPhase);
		const phase = SOCRATIC_PHASES[state.socraticPhase];

		const parts: string[] = [
			`**${phase.name}** (Phase ${state.socraticPhase + 1}/${SOCRATIC_PHASES.length})`,
			"",
			...questions,
		];

		return {
			message: parts.join("\n"),
			state: {
				...newState,
				socraticPhase: state.socraticPhase, // stay until user answers
			},
		};
	}

	// Default: structured questionnaire
	if (signals.length > 0) {
		const questionnaire = generateQuestionnaire(message, signals);
		const formatted = formatQuestionnaire(questionnaire);
		return {
			message: `Ambiguity detected (score: ${score.toFixed(2)}):\n\n${formatted}`,
			state: newState,
		};
	}

	return {
		message: `No ambiguity detected (score: ${score.toFixed(2)}). Ready to proceed.`,
		state: newState,
	};
}

import type { PipelineState } from "../types.ts";
import type { PipelineExtensionConfig } from "../config.ts";
import { transition } from "../plan/plan-mode.ts";
import { selectPipeline, describePipeline } from "../adaptive/pipeline-selector.ts";

export interface GoCommandResult {
	message: string;
	state: PipelineState;
}

/**
 * Handle /go: start execution based on current pipeline state.
 */
export function handleGo(
	state: PipelineState,
	config: PipelineExtensionConfig,
): GoCommandResult {
	// If in IDLE with no plan, suggest /plan first
	if (state.mode === "IDLE") {
		return {
			message: "No plan in progress. Use /plan <task> to start planning first.",
			state,
		};
	}

	// If in READY state, start execution
	if (state.mode === "READY") {
		try {
			const newState = transition(state, "EXECUTING");
			const pipeline = selectPipeline(state.complexity, config);
			return {
				message: `Starting execution!\n${describePipeline(pipeline)}\n\nPlan: "${state.plan?.title ?? "unnamed"}"\nTasks: ${state.plan?.tasks.length ?? 0}`,
				state: newState,
			};
		} catch (err) {
			return {
				message: `Cannot start execution: ${(err as Error).message}`,
				state,
			};
		}
	}

	// If already executing
	if (state.mode === "EXECUTING") {
		return {
			message: `Already executing plan: "${state.plan?.title ?? "unnamed"}" (${state.currentTaskIndex}/${state.plan?.tasks.length ?? 0} tasks done)`,
			state,
		};
	}

	// In other states, suggest the appropriate action
	const suggestions: Record<string, string> = {
		"GATHERING": "Still gathering requirements. Answer clarification questions or describe the task in more detail.",
		"SPEC'ING": "Spec is being generated. Review and approve it.",
		"PLANNING": "Plan is being generated. Review and approve it.",
		"REVIEWING": "Review in progress. Check review results.",
		"COMPLETE": "Pipeline is complete. Use /plan to start a new one.",
	};

	return {
		message: suggestions[state.mode] ?? `Current state: ${state.mode}. Use /plan status for details.`,
		state,
	};
}

import type { ExtensionAPI, ExtensionContext, ExtensionCommandContext } from "@mariozechner/pi-coding-agent";
import { loadConfig } from "../config.ts";
import { registerPipelineTools } from "./tool-registry.ts";
import { emptyPipelineState } from "../types.ts";
import { detectAmbiguity } from "../clarify/ambiguity.ts";
import { totalAmbiguityScore } from "../clarify/scoring.ts";
import { detectComplexity } from "../adaptive/complexity.ts";
import { handlePlan, handlePlanDeepen, handlePlanGo, handlePlanStatus } from "../commands/plan.ts";
import { handlePlanReview } from "../commands/review.ts";
import { handleVerify, handleVerifyEvidence } from "../commands/verify.ts";
import { handleClarify } from "../commands/clarify.ts";
import { handleGo } from "../commands/go.ts";

export function registerPiPipeline(pi: ExtensionAPI): void {
	// Pipeline state is session-scoped
	let state = emptyPipelineState();

	pi.on("session_start", (_event, ctx: ExtensionContext) => {
		const { config } = loadConfig(ctx.cwd);

		if (!config.enabled) return;

		// Reset pipeline state for new session
		state = emptyPipelineState();

		// Register pipeline tools
		registerPipelineTools(pi);

		// Register slash commands
		registerPipelineCommands(pi, ctx, () => state, (s) => { state = s; });
	});

	// Hook: input → intent analysis
	pi.on("input", (event) => {
		const text = event.text;
		if (!text) return;

		const signals = detectAmbiguity(text);
		const score = totalAmbiguityScore(signals);

		if (score > 0.5 && state.mode === "IDLE") {
			// Could inject plan mode prefix for complex requests
			state = { ...state, ambiguityScore: score };
		}
	});

	// Hook: context → pipeline context injection
	pi.on("context", () => {
		if (state.mode === "GATHERING" || state.mode === "SPEC'ING" || state.mode === "PLANNING") {
			return {
				messages: [
					{
						role: "user" as const,
						content: "[system] You are in planning mode. Ask clarifying questions before implementing.",
					},
				],
			};
		}

		if (state.mode === "EXECUTING") {
			return {
				messages: [
					{
						role: "user" as const,
						content: "[system] Follow the approved plan. Report evidence when each task completes.",
					},
				],
			};
		}

		if (state.mode === "REVIEWING") {
			return {
				messages: [
					{
						role: "user" as const,
						content: "[system] Review ONLY what was asked. Do not add scope.",
					},
				],
			};
		}

		return undefined;
	});
}

function registerPipelineCommands(
	pi: ExtensionAPI,
	ctx: ExtensionContext,
	getState: () => typeof import("../types.ts").emptyPipelineState extends () => infer R ? R : never,
	setState: (s: typeof import("../types.ts").emptyPipelineState extends () => infer R ? R : never) => void,
): void {
	const state = getState;
	const set = setState;

	// /plan command
	pi.registerCommand("plan", {
		description: "Plan mode: /plan <task>, /plan deepen, /plan go, /plan status, /plan review",
		async handler(args: string, cmdCtx: ExtensionCommandContext) {
			const { config } = loadConfig(ctx.cwd);
			const arg = args?.trim().toLowerCase() ?? "";

			if (arg.startsWith("deepen")) {
				const result = handlePlanDeepen(state(), (t) => t); // identity analyzer as default
				set(result.state);
				cmdCtx.ui.notify(result.message);
			} else if (arg === "go") {
				const result = handlePlanGo(state());
				set(result.state);
				cmdCtx.ui.notify(result.message);
			} else if (arg === "status") {
				const result = handlePlanStatus(state());
				cmdCtx.ui.notify(result.message);
			} else if (arg === "review") {
				const { createSpecComplianceReview, createCodeQualityReview } = await import("../review/two-stage.ts");
				const stage1 = createSpecComplianceReview();
				const result = handlePlanReview(state(), stage1);
				set(result.state);
				cmdCtx.ui.notify(result.message);
			} else {
				// Use the original (non-lowered) args for the task description
				const taskArgs = args?.trim() ?? "";
				const result = handlePlan(taskArgs, state(), config);
				set(result.state);
				cmdCtx.ui.notify(result.message);
			}
		},
	});

	// /verify command
	pi.registerCommand("verify", {
		description: "Run verification gates: /verify, /verify evidence",
		async handler(args: string, cmdCtx: ExtensionCommandContext) {
			const { config } = loadConfig(ctx.cwd);
			const arg = args?.trim().toLowerCase() ?? "";

			if (arg === "evidence") {
				const taskCtx = {
					changedFiles: [],
					assistantOutput: "",
					hasLsp: false,
					cwd: ctx.cwd,
				};
				const result = handleVerifyEvidence(state(), taskCtx);
				cmdCtx.ui.notify(result.message);
			} else {
				const taskCtx = {
					changedFiles: [],
					assistantOutput: "",
					hasLsp: false,
					cwd: ctx.cwd,
				};
				const result = handleVerify(state(), taskCtx, config);
				cmdCtx.ui.notify(result.message);
			}
		},
	});

	// /clarify command
	pi.registerCommand("clarify", {
		description: "Force clarification: /clarify <message>",
		async handler(args: string, cmdCtx: ExtensionCommandContext) {
			const { config } = loadConfig(ctx.cwd);
			const message = args?.trim() ?? "";
			if (!message) {
				cmdCtx.ui.notify("Usage: /clarify <message to analyze>");
				return;
			}
			const result = handleClarify(message, state(), config);
			set(result.state);
			cmdCtx.ui.notify(result.message);
		},
	});

	// /go command
	pi.registerCommand("go", {
		description: "Start execution of the current plan",
		async handler(_args: string, cmdCtx: ExtensionCommandContext) {
			const { config } = loadConfig(ctx.cwd);
			const result = handleGo(state(), config);
			set(result.state);
			cmdCtx.ui.notify(result.message);
		},
	});
}

import type { ExtensionAPI, ToolDefinition } from "@mariozechner/pi-coding-agent";
import { Type } from "typebox";

interface PipelineToolResult {
	content: Array<{ type: "text"; text: string }>;
	details: { tool: string; status: "ok" | "error" };
	isError?: boolean;
}

function pipelineResult(text: string, isError = false): PipelineToolResult {
	return {
		content: [{ type: "text", text }],
		details: { tool: "pi-pipeline", status: isError ? "error" : "ok" },
		...(isError ? { isError: true as const } : {}),
	};
}

export function registerPipelineTools(pi: ExtensionAPI): void {
	// pipeline_status
	pi.registerTool({
		name: "pipeline_status",
		label: "Pipeline Status",
		description: "Get the current pipeline state including plan mode, task progress, and complexity level.",
		parameters: Type.Object({}) as never,
		async execute(_id, _params, _signal, _onUpdate, _ctx) {
			try {
				// Return a placeholder status — real state is in the session
				return pipelineResult("Pipeline status: use /plan status for current state.");
			} catch (error) {
				return pipelineResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);

	// pipeline_verify
	pi.registerTool({
		name: "pipeline_verify",
		label: "Pipeline Verify",
		description: "Run verification gates for the current task. Checks tests, typecheck, lint, regression, and evidence completeness.",
		parameters: Type.Object({
			testCommand: Type.Optional(Type.String({ description: "Test command to run for verification." })),
			changedFiles: Type.Optional(Type.Array(Type.String(), { description: "List of changed files." })),
			assistantOutput: Type.Optional(Type.String({ description: "Recent assistant output for evidence check." })),
		}) as never,
		async execute(_id, params, _signal, _onUpdate, _ctx) {
			const p = params as {
				testCommand?: string;
				changedFiles?: string[];
				assistantOutput?: string;
			};

			try {
				const { runGates } = await import("../verify/gates.ts");
				const { checkStopTheLine, formatStopTheLine } = await import("../verify/stop-the-line.ts");

				const ctx = {
					testCommand: p.testCommand,
					changedFiles: p.changedFiles ?? [],
					assistantOutput: p.assistantOutput ?? "",
					hasLsp: false,
					cwd: _ctx.cwd,
				};

				const gateIds = ["tests", "typecheck", "lint", "regression", "evidence"];
				const results = runGates(ctx, gateIds);
				const blockingIds = ["tests", "typecheck", "regression", "evidence"];
				const stopResult = checkStopTheLine(results, blockingIds);

				const parts: string[] = [];
				if (stopResult.blocked) {
					parts.push(formatStopTheLine(stopResult));
					parts.push("");
				}

				parts.push("Gate Results:");
				for (const r of results) {
					parts.push(`  ${r.passed ? "✅" : "❌"} ${r.gateId}: ${r.message}`);
				}

				return pipelineResult(parts.join("\n"));
			} catch (error) {
				return pipelineResult(error instanceof Error ? error.message : String(error), true);
			}
		},
	} satisfies ToolDefinition);
}

